{"code": "import json
import re

# Load data from the stored file paths
with open(locals()['var_functions.query_db:8']) as f:
    pkg_data = json.load(f)
with open(locals()['var_functions.query_db:10']) as f:
    ver_data = json.load(f)  
with open(locals()['var_functions.query_db:12']) as f:
    proj_data = json.load(f)

# Process packages to find latest NPM releases
latest_packages = {}
for p in pkg_data:
    if p.get('System') == 'NPM':
        try:
            vi = json.loads(p['VersionInfo'].strip())
            if vi.get('IsRelease'):
                name = p['Name']
                if name not in latest_packages or vi['Ordinal'] > latest_packages[name]['ordinal']:
                    latest_packages[name] = {
                        'version': p['Version'],
                        'ordinal': vi['Ordinal']
                    }
        except:
            pass

# Extract stars from project descriptions
proj_stars = {}
for proj in proj_data:
    info = proj.get('Project_Information', '')
    if info:
        # Find stars count
        m = re.search(r'(\d{1,3}(?:,\d{3})*)\s+stars?', str(info), re.I)
        if m:
            stars = int(m.group(1).replace(',', ''))
            if stars > 0:
                # Find repo name
                m2 = re.search(r'(\w[-\w]*\/\w[-\w]*)', str(info))
                if m2:
                    proj_stars[m2.group(1)] = stars

# Match packages with project stars
results = []
ver_dict = {(v['System'], v['Name'], v['Version']): v for v in ver_data}

for pkg_name, pkg_info in latest_packages.items():
    key = ('NPM', pkg_name, pkg_info['version'])
    if key in ver_dict:
        proj_name = ver_dict[key]['ProjectName']
        if proj_name in proj_stars:
            results.append({
                'package': pkg_name,
                'version': pkg_info['version'],
                'stars': proj_stars[proj_name],
                'project': proj_name
            })

# Sort by stars and get top 5
top5 = sorted(results, key=lambda x: x['stars'], reverse=True)[:5]

# Format output
output = []
for r in top5:
    output.append(r['package'] + ' version ' + r['version'] + ' - ' + str(r['stars']) + ' GitHub stars')

print('__RESULT__:')
print('\n'.join(output) if output else 'No results found')"}

